$(document).ready(function(){var d=$('#flash-messages').data('messages');if(d){d.forEach(function(msg){var category=msg[0],message=msg[1],icon='info',bgColor='#0d6efd';if(category==='success'){icon='success';bgColor='#198754'}else if(category==='error'){icon='error';bgColor='#dc3545'}else if(category==='warning'){icon='warning';bgColor='#ffc107'}Swal.fire({toast:true,position:'top-end',icon:icon,title:message,showConfirmButton:false,timer:3000,timerProgressBar:true,background:bgColor,color:'#fff'})})}});function confirmLogout(event){event.preventDefault();Swal.fire({title:'Yakin ingin logout?',icon:'question',showCancelButton:true,confirmButtonText:'Ya, Logout',cancelButtonText:'Batal'}).then(function(result){if(result.isConfirmed){window.location.href='/auth/logout'}})}function getCSRFToken(){var m=document.querySelector('meta[name="csrf-token"]');return m?m.getAttribute('content'):''}function confirmHapus(url,nama){Swal.fire({title:'Hapus '+nama+'?',text:'Data akan dihapus secara soft-delete.',icon:'warning',showCancelButton:true,confirmButtonColor:'#dc3545',confirmButtonText:'Ya, Hapus',cancelButtonText:'Batal'}).then(function(result){if(result.isConfirmed){var f=document.createElement('form');f.method='POST';f.action=url;var c=document.createElement('input');c.type='hidden';c.name='csrf_token';c.value=getCSRFToken();f.appendChild(c);document.body.appendChild(f);f.submit()}});return false}function confirmToggleAktif(url,username,isActive){var a=isActive?'Nonaktifkan':'Aktifkan',t=isActive?'Ya, Nonaktifkan':'Ya, Aktifkan',c=isActive?'#dc3545':'#198754';Swal.fire({title:a+' user '+username+'?',icon:'warning',showCancelButton:true,confirmButtonColor:c,confirmButtonText:t,cancelButtonText:'Batal'}).then(function(result){if(result.isConfirmed){var f=document.createElement('form');f.method='POST';f.action=url;var i=document.createElement('input');i.type='hidden';i.name='csrf_token';i.value=getCSRFToken();f.appendChild(i);document.body.appendChild(f);f.submit()}});return false}function confirmKunciNilai(form){Swal.fire({title:'Kunci nilai ini?',text:'Nilai tidak dapat diubah setelah dikunci.',icon:'warning',showCancelButton:true,confirmButtonColor:'#198754',confirmButtonText:'Ya, Kunci',cancelButtonText:'Batal'}).then(function(result){if(result.isConfirmed){form.submit()}});return false}document.addEventListener('DOMContentLoaded',function(){[].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]')).forEach(function(el){new bootstrap.Tooltip(el)});if(typeof $.fn.DataTable!=='undefined'){$.fn.DataTable.ext.pager.numbers_length=5}});
function renderBarChart(e,t,n,o){var r=document.getElementById(e);if(!r)return;new Chart(r.getContext('2d'),{type:'bar',data:{labels:t,datasets:[{label:o||'Rata-rata Nilai',data:n,backgroundColor:'rgba(13,110,253,0.6)',borderColor:'rgba(13,110,253,1)',borderWidth:1}]},options:{responsive:true,maintainAspectRatio:false,devicePixelRatio:window.devicePixelRatio||1,scales:{y:{beginAtZero:true,max:100}}}})}function renderDoughnutChart(e,t,n){var r=document.getElementById(e);if(!r)return;new Chart(r.getContext('2d'),{type:'doughnut',data:{labels:['Lulus','Tidak Lulus'],datasets:[{data:[t,n],backgroundColor:['rgba(25,135,84,0.8)','rgba(220,53,69,0.8)'],borderColor:['#198754','#dc3545'],borderWidth:1}]},options:{responsive:true,maintainAspectRatio:false,devicePixelRatio:window.devicePixelRatio||1,plugins:{legend:{position:'bottom'}}}})}function renderRadarChart(e,t,n){var r=document.getElementById(e);if(!r)return;new Chart(r.getContext('2d'),{type:'radar',data:{labels:t,datasets:[{label:'Nilai',data:n,backgroundColor:'rgba(13,110,253,0.2)',borderColor:'rgba(13,110,253,1)',borderWidth:2,pointBackgroundColor:'rgba(13,110,253,1)'}]},options:{responsive:true,scales:{r:{beginAtZero:true,max:100}}}})}
function hitungNilaiAkhir(t,uts,uas){return(0.30*t)+(0.30*uts)+(0.40*uas)}
